import{_ as a,o,c as t,a2 as r}from"./chunks/framework.IwO0Hdn_.js";const u=JSON.parse('{"title":"[DATA] F-03.5 — Log Archivado es Persistente y No Expirable","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-03.5_log_persistente.md","filePath":"backlog/F-03.5_log_persistente.md","lastUpdated":null}'),i={name:"backlog/F-03.5_log_persistente.md"};function n(s,e,c,d,l,p){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="data-f-03-5-—-log-archivado-es-persistente-y-no-expirable" tabindex="-1">[DATA] F-03.5 — Log Archivado es Persistente y No Expirable <a class="header-anchor" href="#data-f-03-5-—-log-archivado-es-persistente-y-no-expirable" aria-label="Permalink to &quot;[DATA] F-03.5 — Log Archivado es Persistente y No Expirable&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-03 — Detalle y Archivado de un Log</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Data</code><strong>Impacta en:</strong> Equipo Base de Datos + Equipo Backend (Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.2_migraciones_modelos.html">F-00.2</a></td><td>Tabla <code>archived_logs</code> sin TTL definida en las migraciones</td></tr><tr><td><a href="./F-05.1_conexion_postgresql.html">F-05.1</a></td><td>Usuario BD con permisos mínimos (sin DELETE sobre <code>archived_logs</code>) configurado</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero que los logs archivados nunca se borren automáticamente ni tengan fecha de expiración Para garantizar que el histórico sirve como registro permanente de auditoría</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Persistencia):</strong> Dado que un log fue archivado hace 2 años, cuando accedo al histórico, entonces el log y todos sus comentarios siguen siendo accesibles y completos.</li><li>[ ] <strong>Escenario 2 (Sin TTL):</strong> Dado que la tabla <code>archived_logs</code> tiene registros de cualquier fecha, cuando un proceso de mantenimiento se ejecuta, entonces no se ejecuta ninguna limpieza o expiración automática sobre esta tabla.</li><li>[ ] <strong>Escenario 3 (Sin borrado manual):</strong> Dado que el administrador usa el panel, cuando navega por el histórico, entonces no existe ningún botón o acción de &quot;eliminar&quot; en la interfaz de usuario por defecto. <strong>Excepción controlada:</strong> la feature F-04.9 (COULD, Sprint 4) introduce un borrado de administración excepcional — solo se implementa si se aprueba.</li><li>[ ] <strong>Requisito Técnico:</strong> El usuario de DB del panel NO tiene permisos <code>DELETE</code> ni <code>TRUNCATE</code> sobre <code>archived_logs</code> (STRIDE T-DB-01). No configurar políticas de retención (TTL) sobre esta tabla. Considerar particionado por año a futuro si el volumen supera 1M de registros (NFR-ESC-03).</li></ul>',12)])])}const h=a(i,[["render",n]]);export{u as __pageData,h as default};
